What does this program print?

```cpp
#include <iostream>
#include <string>
class Base {
public:
    int x = 10;
    void show() { std::cout << "x=" << x << "\n"; }
};
class Derived : public Base {
public:
    int y = 20;
};
int main() {
    Derived d;
    d.x = 5;
    d.show();
    std::cout << d.y << "\n";
}
```

